=<!DOCTYPE html>
<html dir="ltr" lang="en">
<head>
<meta charset="UTF-8">
<style>
  body {
    font-family: Arial, sans-serif;
    background: #E6F4F6;
    padding: 20px;
    direction: ltr;
    margin: 0;
  }
  .container {
    max-width: 600px;
    margin: auto;
    background: #F4F8FA;
    border-radius: 12px;
    padding: 30px;
    box-shadow: 0 4px 6px rgba(0,0,0,0.05);
    border: 1px solid #6B7280;
  }
  .header {
    background: #0D3B4E;
    color: #F4F8FA;
    padding: 20px 24px;
    border-radius: 10px;
    text-align: center;
    margin-bottom: 24px;
  }
  .header h1 { margin: 0 0 6px 0; font-size: 24px; }
  .header p { margin: 0; color: #A8D5DC; font-size: 15px; }
  .section { margin-bottom: 18px; }
  .section p { color: #0D3B4E; margin: 0 0 8px 0; font-size: 14px; line-height: 1.6; }
  .stats-row {
    display: flex;
    gap: 12px;
    margin: 20px 0;
  }
  .stat-card {
    flex: 1;
    background: #E6F4F6;
    border-radius: 8px;
    padding: 14px 16px;
    border: 1px solid #B8D4DA;
    text-align: center;
  }
  .stat-label {
    font-size: 11px;
    color: #6B7280;
    text-transform: uppercase;
    letter-spacing: 0.6px;
    margin-bottom: 4px;
  }
  .stat-value {
    font-size: 22px;
    font-weight: bold;
    color: #0D3B4E;
  }
  .stat-unit { font-size: 13px; font-weight: normal; color: #6B7280; }
  .promo {
    background: #E6F4F6;
    padding: 20px;
    margin: 20px 0;
    border-radius: 10px;
    text-align: center;
    border: 2px dashed #0A7C8C;
  }
  .promo p { margin: 0 0 6px 0; font-weight: bold; color: #0D3B4E; font-size: 14px; }
  .code {
    font-size: 30px;
    font-weight: bold;
    color: #20B2BF;
    margin: 10px 0;
    letter-spacing: 2px;
  }
  .promo-sub { color: #6B7280!important; font-size: 13px!important; font-weight: normal!important; }
  .footer {
    text-align: center;
    margin-top: 24px;
    padding-top: 18px;
    border-top: 1px solid #C8D8DE;
  }
  .footer p { color: #6B7280; font-size: 12px; margin: 4px 0; }
  .cta {
    display: inline-block;
    margin: 16px 0 8px;
    background: #0A7C8C;
    color: #F4F8FA;
    padding: 12px 28px;
    border-radius: 8px;
    font-weight: bold;
    font-size: 14px;
    text-decoration: none;
  }
</style>
</head>
<body>
<div class="container">

  <!-- HEADER -->
  <div class="header">
    <h1>Ridelytics</h1>
    <p>We miss you, {{ $('SQL Fetch Data').item.json.FirstName }}!</p>
  </div>

  <!-- GREETING -->
  <div class="section">
    <p>Hello <strong>{{ $('SQL Fetch Data').item.json.FirstName }} {{ $('SQL Fetch Data').item.json.LastName }}</strong>,</p>
    <p>It has been a while since your last ride with us, and we noticed you haven't been around lately. As one of our valued passengers, we'd love to welcome you back with an exclusive offer just for you.</p>
  </div>

  <!-- STATS -->
  <div class="stats-row">
    <div class="stat-card">
      <div class="stat-label">Days Since Last Ride</div>
      <div class="stat-value">{{ $('SQL Fetch Data').item.json.DaysSinceLastTrip }} <span class="stat-unit">days</span></div>
    </div>
    <div class="stat-card">
      <div class="stat-label">Total Trips</div>
      <div class="stat-value">{{ $('SQL Fetch Data').item.json.TotalTrips }} <span class="stat-unit">trips</span></div>
    </div>
    <div class="stat-card">
      <div class="stat-label">Total Spend</div>
      <div class="stat-value">{{ $('SQL Fetch Data').item.json.TotalSpend }} <span class="stat-unit">EGP</span></div>
    </div>
  </div>

  <!-- PROMO -->
  <div class="promo">
    <p>Your Exclusive Promo Code</p>
    <div class="code">{{ $('SQL Fetch Data').item.json.PromoCode }}</div>
    <p>Get <strong>15% OFF</strong> your next ride</p>
    <p class="promo-sub">Valid for 14 days from the date of this email &nbsp;·&nbsp; Single use only</p>
  </div>

  <!-- FOOTER -->
  <div class="footer">
    <p>This offer was sent to <strong>{{ $('SQL Fetch Data').item.json.Email }}</strong></p>
    <p style="margin-top:10px;">© 2025 Ridelytics · Egypt · All rights reserved</p>
    <p>If you did not request this email, please ignore it.</p>
  </div>

</div>
</body>
</html>
